+// parseActivityTimestamp parses a Unix timestamp string from tmux.
+// Returns (0, false) for invalid or zero timestamps.
+func parseActivityTimestamp(s string) (int64, bool) {
+	var unix int64
+	if _, err := fmt.Sscanf(s, "%d", &unix); err != nil || unix <= 0 {
+		return 0, false
+	}
+	return unix, true
 }

